#include<bits/stdc++.h>
using namespace std;
#define int  long long
int n, m, k, ans = 0, l = 1, r;
struct node {

		int p, c;
};
node a[100005], b[100005];
bool c1 (const node &a, const node &b) {
	return a.p < b.p;
}
bool c2(const node &a, const node &b) {
	return abs(a.p - a.c) > abs(b.p - b.c);
}
signed main() {
	cin >> n >> m >> k;
	r = n;
	for (int i = 1; i <= n; i++) cin >> a[i].p >> a[i].c;
	for (int i = 1; i <= m; i++) cin >> b[i].p >> b[i].c;
	sort(a + 1, a + n + 1, c1);
	sort(b + 1, b + m + 1, c2);
	for (int i = 0; i <= m; i++) {
		if (b[i].p - b[i].c == 0) {
			ans += (b[i].c * k);
		} else if (b[i].p - b[i].c > 0) {
			if (a[l].c  <= 0) l++;
			ans += (b[i].c  * k + (b[i].p - b[i].c) * a[l].p);
			a[l].c--;
		} else {
			if (a[r].c <= 0) r--;
			ans += (b[i].c * k + (b[i].p - b[i].c) * a[r].p);
			a[r].c--;
		}
	}
	cout << ans * 2;
	return 0;
}
